use strict;
use warnings;

# for dongusu
print "1'den 5'e kadar:\n";
for (my $i = 1; $i <= 5; $i++) {
    print "Sayi: $i\n";
}

# while dongusu
print "\nGeri sayim:\n";
my $counter = 5;
while ($counter > 0) {
    print "$counter\n";
    $counter--;
}

# foreach dongusu
print "\nMeyveler:\n";
my @fruits = ("Elma", "Armut", "Muz", "Karpuz");
foreach my $fruit (@fruits) {
    print "- $fruit\n";
}

# foreach ile indeks
print "\nIndeksli liste:\n";
for my $i (0 .. $#fruits) {
    print "$i: $fruits[$i]\n";
}

# do-while benzeri
print "\nDo-while ornegi:\n";
my $n = 0;
do {
    print "n = $n\n";
    $n++;
} while ($n < 3);
